-- Dangerous:
CREATE TABLE orders (
  customer_id INTEGER REFERENCES customers(id)
    ON DELETE CASCADE  -- "just delete everything lol"
);

-- Safer:
CREATE TABLE orders (
  customer_id INTEGER REFERENCES customers(id)
    ON DELETE RESTRICT  -- "stop and think first"
);

-- Compromise:
CREATE TABLE orders (
  customer_id INTEGER REFERENCES customers(id)
    ON DELETE SET NULL  -- preserves the order, loses the link
);

-- Slower (IN materializes all matching IDs):
SELECT * FROM users
WHERE id IN (
  SELECT user_id FROM orders
  WHERE amount > 1000
);

-- Faster (EXISTS stops at first match):
SELECT * FROM users u
WHERE EXISTS (
  SELECT 1 FROM orders o
  WHERE o.user_id = u.id
  AND o.amount > 1000
);

-- Incomplete (NULL sneaks through):
CREATE TABLE metrics (
  completion_pct NUMERIC(5,2)
    CHECK (completion_pct BETWEEN 0 AND 100)
);
-- INSERT INTO metrics (completion_pct) VALUES (NULL);  -- succeeds!

-- Complete (airtight):
CREATE TABLE metrics (
  completion_pct NUMERIC(5,2) NOT NULL
    CHECK (completion_pct BETWEEN 0 AND 100)
);
-- INSERT INTO metrics (completion_pct) VALUES (NULL);  -- rejected!

-- Safe way to EXPLAIN ANALYZE destructive queries:
BEGIN;
EXPLAIN (ANALYZE, BUFFERS)
  DELETE FROM orders WHERE created_at < '2020-01-01';
ROLLBACK;  -- undo the delete, keep the plan
